// 🔍 Look for your count variables or active loop filters inside FilterTabs:

export default function FilterTabs({ filter, setFilter, tasks = [] }) {
  // 🔌 ADD SAFEGUARDS HERE: Add "t &&" before checking status
  const allCount       = tasks.filter(t => t).length;
  const pendingCount   = tasks.filter(t => t && t.status === "pending").length;
  const completedCount = tasks.filter(t => t && t.status === "completed").length;

  return (
    <div className="flex gap-2 mb-6 border-b border-gray-100 pb-2">
      <button
        onClick={() => setFilter("all")}
        className={`px-4 py-2 text-sm font-medium rounded-xl transition-colors ${
          filter === "all" ? "bg-indigo-50 text-indigo-600" : "text-gray-500 hover:bg-gray-50"
        }`}
      >
        All ({allCount})
      </button>
      
      <button
        onClick={() => setFilter("pending")}
        className={`px-4 py-2 text-sm font-medium rounded-xl transition-colors ${
          filter === "pending" ? "bg-yellow-50 text-yellow-700" : "text-gray-500 hover:bg-gray-50"
        }`}
      >
        Pending ({pendingCount})
      </button>

      <button
        onClick={() => setFilter("completed")}
        className={`px-4 py-2 text-sm font-medium rounded-xl transition-colors ${
          filter === "completed" ? "bg-green-50 text-green-700" : "text-gray-500 hover:bg-gray-50"
        }`}
      >
        Completed ({completedCount})
      </button>
    </div>
  );
}
